class User {
    protected String name;
    protected String email;

    User(String name, String email) {
        this.name = name;
        this.email = email;
    }

    String greet() {
        return "Hi, I'm " + name;
    }
}

class AdminUser extends User {
    private String department;

    AdminUser(String name, String email, String department) {
        super(name, email);  // MUST call parent constructor first
        this.department = department;
    }

    String deletePost(int postId) {
        return name + " deleted post " + postId;
    }
}

public class Main {
    public static void main(String[] args) {
        AdminUser admin = new AdminUser("Alex", "alex@example.com", "Engineering");
        System.out.println(admin.greet());          // inherited!
        System.out.println(admin.deletePost(42));   // own method
        System.out.println(admin.name);             // inherited field
    }
}

