class User {
    protected String name;
    User(String name) { this.name = name; }
    String greet()    { return "Hi, I'm " + name; }
    String describe() { return "User: " + name; }
}

class AdminUser extends User {
    AdminUser(String name) { super(name); }

    // TODO: override greet() to append " (Admin)" using super.greet()
    @Override
    String greet() {
        return super.greet() + " (Admin)";
    }

