        System.out.println(admin.describe());
    }
}

class Animal { String name; Animal(String n){ name=n; } }
class Dog extends Animal { void bark(){ System.out.println(name+" barks!"); } Dog(String n){ super(n); } }
class Cat extends Animal { void meow(){ System.out.println(name+" meows!"); } Cat(String n){ super(n); } }

public class Main {
    public static void main(String[] args) {
        Animal[] animals = {
            new Dog("Rex"),
            new Cat("Whiskers"),
            new Dog("Buddy")
        };

        for (Animal a : animals) {
            if (a instanceof Dog d) {
                d.bark();  // d is already a Dog — no cast needed!
            } else if (a instanceof Cat c) {
                c.meow();
            }

            System.out.println(a.name + " instanceof Animal: " + (a instanceof Animal));
        }
    }
}

abstract class Shape {
    abstract double area();   // subclasses MUST implement
    abstract double perimeter();

    // Non-abstract method — shared by all shapes:
    String describe() {
        return String.format("%s: area=%.2f, perimeter=%.2f",
            getClass().getSimpleName(), area(), perimeter());
    }
}

class Circle extends Shape {
    private double radius;
    Circle(double r) { radius = r; }
    @Override double area()      { return Math.PI * radius * radius; }
    @Override double perimeter() { return 2 * Math.PI * radius; }
}

class Rectangle extends Shape {
    private double w, h;
    Rectangle(double w, double h) { this.w=w; this.h=h; }
    @Override double area()      { return w * h; }
    @Override double perimeter() { return 2 * (w + h); }
}

public class Main {
    public static void main(String[] args) {
        Shape[] shapes = {new Circle(5), new Rectangle(4, 6)};
        for (Shape s : shapes) System.out.println(s.describe());
    }
}
